export function getLessonById(id: string): Lesson | undefined {
  return LESSONS.find((lesson) => lesson.id === id);
}

export function getLessonsByModule(module: number): Lesson[] {
  return LESSONS.filter((lesson) => lesson.module === module).sort((a, b) => a.order - b.order);
}

export function getLessonVocabulary(id: string): VocabularyItem[] {
  const lesson = LESSONS.find((lesson) => lesson.id === id);
  return lesson ? lesson.vocabulary : [];
}

export function getModules(): Module[] {
  const modulesSet = new Set<number>();
  LESSONS.forEach((lesson) => modulesSet.add(lesson.module));
  const moduleNumbers = Array.from(modulesSet).sort((a, b) => a - b);
  return moduleNumbers.map((num) => ({
    number: num,
    name: MODULE_NAMES[num as keyof typeof MODULE_NAMES] || `Module ${num}`,
    lessons: getLessonsByModule(num),
  })) as Module[];
}

export function getNextLesson(currentLessonId: string): Lesson | undefined {
  const currentLesson = getLessonById(currentLessonId);
  if (!currentLesson) return undefined;

  const moduleLessons = getLessonsByModule(currentLesson.module);
  const currentIndex = moduleLessons.findIndex((l) => l.id === currentLessonId);

  if (currentIndex < moduleLessons.length - 1) {
    return moduleLessons[currentIndex + 1];
  }

  const nextModule = currentLesson.module + 1;
  const nextModuleLessons = getLessonsByModule(nextModule);
  return nextModuleLessons.length > 0 ? nextModuleLessons[0] : undefined;
}

export function getCourseStats() {
  const totalLessons = LESSONS.length;
  const totalVocab = LESSONS.reduce((sum, l) => sum + (l.vocabulary?.length || 0), 0);
  const moduleCounts: Record<number, number> = {};
  LESSONS.forEach((l) => {
    moduleCounts[l.module] = (moduleCounts[l.module] || 0) + 1;
  });
  return {
    totalLessons,
    totalVocabulary: totalVocab,
    moduleCounts,
    modules: Object.keys(MODULE_NAMES).length,
  };
}
